class Solution {
public:
    bool isPossible(vector<int>& nums) {
        int count = 0;
        for (int i = 2; i < nums.size(); i++) {
            if (nums[i] == nums[i - 1] + 1 && nums[i - 1] == nums[i - 2] + 1) {
                count++;
            }
        }
        return count >= 3;
    }
};
